SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ----------------------------
-- Table structure for config_info
-- ----------------------------
DROP TABLE IF EXISTS `config_info`;
CREATE TABLE `config_info`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `data_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'data_id',
  `group_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `content` longtext CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'content',
  `md5` varchar(32) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'md5',
  `gmt_create` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `gmt_modified` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
  `src_user` text CHARACTER SET utf8 COLLATE utf8_bin NULL COMMENT 'source user',
  `src_ip` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'source ip',
  `app_name` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT '租户字段',
  `c_desc` varchar(256) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `c_use` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `effect` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `type` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `c_schema` text CHARACTER SET utf8 COLLATE utf8_bin NULL,
  `encrypted_data_key` text CHARACTER SET utf8 COLLATE utf8_bin NULL COMMENT '秘钥',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_configinfo_datagrouptenant`(`data_id`, `group_id`, `tenant_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 101 CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = 'config_info' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of config_info
-- ----------------------------
INSERT INTO `config_info` VALUES (1, 'application-dev.yml', 'DEFAULT_GROUP', 'spring:\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n\n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n  okhttp:\n    enabled: true\n  httpclient:\n    enabled: false\n  client:\n    config:\n      default:\n        connectTimeout: 10000\n        readTimeout: 10000\n  compression:\n    request:\n      enabled: true\n    response:\n      enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \'*\'\n', 'aaa73b809cfd4d0058893aa13da57806', '2020-05-20 12:00:00', '2022-04-24 10:26:34', 'nacos', '0:0:0:0:0:0:0:1', '', '', '通用配置', 'null', 'null', 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (2, 'ruoyi-gateway-dev.yml', 'DEFAULT_GROUP', 'spring:\n  redis:\n    host: localhost\n    port: 6379\n    password: \n  cloud:\n    gateway:\n      discovery:\n        locator:\n          lowerCaseServiceId: true\n          enabled: true\n      routes:\n        # 认证中心\n        - id: ruoyi-auth\n          uri: lb://ruoyi-auth\n          predicates:\n            - Path=/auth/**\n          filters:\n            # 验证码处理\n            - CacheRequestFilter\n            - ValidateCodeFilter\n            - StripPrefix=1\n        # 代码生成\n        - id: ruoyi-gen\n          uri: lb://ruoyi-gen\n          predicates:\n            - Path=/code/**\n          filters:\n            - StripPrefix=1\n        # 定时任务\n        - id: ruoyi-job\n          uri: lb://ruoyi-job\n          predicates:\n            - Path=/schedule/**\n          filters:\n            - StripPrefix=1\n        # 系统模块\n        - id: ruoyi-system\n          uri: lb://ruoyi-system\n          predicates:\n            - Path=/system/**\n          filters:\n            - StripPrefix=1\n        # 文件服务\n        - id: ruoyi-file\n          uri: lb://ruoyi-file\n          predicates:\n            - Path=/file/**\n          filters:\n            - StripPrefix=1\n\n# 安全配置\nsecurity:\n  # 验证码\n  captcha:\n    enabled: true\n    type: math\n  # 防止XSS攻击\n  xss:\n    enabled: true\n    excludeUrls:\n      - /system/notice\n  # 不校验白名单\n  ignore:\n    whites:\n      - /auth/logout\n      - /auth/login\n      - /auth/register\n      - /*/v2/api-docs\n      - /csrf\n', '2f5a6b5a4ccf20b5801c5cf842456ec6', '2020-05-14 14:17:55', '2021-07-30 09:07:14', NULL, '0:0:0:0:0:0:0:1', '', '', '网关模块', 'null', 'null', 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (3, 'ruoyi-auth-dev.yml', 'DEFAULT_GROUP', 'spring: \r\n  redis:\r\n    host: localhost\r\n    port: 6379\r\n    password: \r\n', 'b7354e1eb62c2d846d44a796d9ec6930', '2020-11-20 00:00:00', '2021-02-28 21:06:58', NULL, '0:0:0:0:0:0:0:1', '', '', '认证中心', 'null', 'null', 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (4, 'ruoyi-monitor-dev.yml', 'DEFAULT_GROUP', '# spring\r\nspring: \r\n  security:\r\n    user:\r\n      name: ruoyi\r\n      password: 123456\r\n  boot:\r\n    admin:\r\n      ui:\r\n        title: 若依服务状态监控\r\n', 'd8997d0707a2fd5d9fc4e8409da38129', '2020-11-20 00:00:00', '2020-12-21 16:28:07', NULL, '0:0:0:0:0:0:0:1', '', '', '监控中心', 'null', 'null', 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (5, 'ruoyi-system-dev.yml', 'DEFAULT_GROUP', '# spring配置\nspring: \n  redis:\n    host: localhost\n    port: 6379\n    password: \n  datasource:\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: admin\n        loginPassword: 123456\n    dynamic:\n      druid:\n        initial-size: 5\n        min-idle: 5\n        maxActive: 20\n        maxWait: 60000\n        timeBetweenEvictionRunsMillis: 60000\n        minEvictableIdleTimeMillis: 300000\n        validationQuery: SELECT 1 FROM DUAL\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        filters: stat,slf4j\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n      datasource:\n          # 主库数据源\n          master:\n            driver-class-name: com.mysql.cj.jdbc.Driver\n            url: jdbc:mysql://localhost:3306/ry-cloud?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\n            username: root\n            password: root\n          # 从库数据源\n          # slave:\n            # username: \n            # password: \n            # url: \n            # driver-class-name: \n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\n\n# seata配置\nseata:\n  # 默认关闭，如需启用spring.datasource.dynami.seata需要同时开启\n  enabled: false\n  # Seata 应用编号，默认为 ${spring.application.name}\n  application-id: ${spring.application.name}\n  # Seata 事务组编号，用于 TC 集群名\n  tx-service-group: ${spring.application.name}-group\n  # 关闭自动代理\n  enable-auto-data-source-proxy: false\n  # 服务配置项\n  service:\n    # 虚拟组和分组的映射\n    vgroup-mapping:\n      ruoyi-system-group: default\n  config:\n    type: nacos\n    nacos:\n      serverAddr: 127.0.0.1:8848\n      group: SEATA_GROUP\n      namespace:\n  registry:\n    type: nacos\n    nacos:\n      application: seata-server\n      server-addr: 127.0.0.1:8848\n      namespace:\n\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.ruoyi.system\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# 日志记录输出配置\nlogging:\n  level:\n    com:\n      ruoyi:\n        system:\n          mapper: debug\n          \n# swagger配置\nswagger:\n  title: 系统模块接口文档\n  license: Powered By ruoyi\n  licenseUrl: https://ruoyi.vip', 'f940f72f27e2d319e531576d72fc1497', '2020-11-20 00:00:00', '2022-07-30 09:13:52', 'nacos', '0:0:0:0:0:0:0:1', '', '', '系统模块', 'null', 'null', 'yaml', '', '');
INSERT INTO `config_info` VALUES (6, 'ruoyi-gen-dev.yml', 'DEFAULT_GROUP', '# spring配置\nspring: \n  redis:\n    host: localhost\n    port: 6379\n    password: \n  datasource: \n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://localhost:3306/ry-cloud?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\n    username: root\n    password: root\n\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.ruoyi.gen.domain\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# swagger配置\nswagger:\n  title: 代码生成接口文档\n  license: Powered By ruoyi\n  licenseUrl: https://ruoyi.vip\n\n# 代码生成\ngen: \n  # 作者\n  author: ruoyi\n  # 默认生成包路径 system 需改成自己的模块名称 如 system monitor tool\n  packageName: com.ruoyi.system\n  # 自动去除表前缀，默认是false\n  autoRemovePre: false\n  # 表前缀（生成类名不会包含表前缀，多个用逗号分隔）\n  tablePrefix: sys_\n', '456d6438fe5dd982d10739c2eb35b95a', '2020-11-20 00:00:00', '2022-07-30 07:51:04', 'nacos', '0:0:0:0:0:0:0:1', '', '', '代码生成', 'null', 'null', 'yaml', '', '');
INSERT INTO `config_info` VALUES (7, 'ruoyi-job-dev.yml', 'DEFAULT_GROUP', '# spring配置\nspring: \n  redis:\n    host: localhost\n    port: 6379\n    password: \n  datasource:\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://localhost:3306/ry-cloud?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\n    username: root\n    password: root\n\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.ruoyi.job.domain\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# swagger配置\nswagger:\n  title: 定时任务接口文档\n  license: Powered By ruoyi\n  licenseUrl: https://ruoyi.vip\n', '32869775f1fedc3c3fcb2aace20252b5', '2020-11-20 00:00:00', '2022-07-30 07:51:17', 'nacos', '0:0:0:0:0:0:0:1', '', '', '定时任务', 'null', 'null', 'yaml', '', '');
INSERT INTO `config_info` VALUES (8, 'ruoyi-file-dev.yml', 'DEFAULT_GROUP', '# 本地文件上传    \r\nfile:\r\n    domain: http://127.0.0.1:9300\r\n    path: D:/ruoyi/uploadPath\r\n    prefix: /statics\r\n\r\n# FastDFS配置\r\nfdfs:\r\n  domain: http://8.129.231.12\r\n  soTimeout: 3000\r\n  connectTimeout: 2000\r\n  trackerList: 8.129.231.12:22122\r\n\r\n# Minio配置\r\nminio:\r\n  url: http://8.129.231.12:9000\r\n  accessKey: minioadmin\r\n  secretKey: minioadmin\r\n  bucketName: test', '5382b93f3d8059d6068c0501fdd41195', '2020-11-20 00:00:00', '2020-12-21 21:01:59', NULL, '0:0:0:0:0:0:0:1', '', '', '文件服务', 'null', 'null', 'yaml', NULL, '');
INSERT INTO `config_info` VALUES (9, 'sentinel-ruoyi-gateway', 'DEFAULT_GROUP', '[\r\n    {\r\n        \"resource\": \"ruoyi-auth\",\r\n        \"count\": 500,\r\n        \"grade\": 1,\r\n        \"limitApp\": \"default\",\r\n        \"strategy\": 0,\r\n        \"controlBehavior\": 0\r\n    },\r\n	{\r\n        \"resource\": \"ruoyi-system\",\r\n        \"count\": 1000,\r\n        \"grade\": 1,\r\n        \"limitApp\": \"default\",\r\n        \"strategy\": 0,\r\n        \"controlBehavior\": 0\r\n    },\r\n	{\r\n        \"resource\": \"ruoyi-gen\",\r\n        \"count\": 200,\r\n        \"grade\": 1,\r\n        \"limitApp\": \"default\",\r\n        \"strategy\": 0,\r\n        \"controlBehavior\": 0\r\n    },\r\n	{\r\n        \"resource\": \"ruoyi-job\",\r\n        \"count\": 300,\r\n        \"grade\": 1,\r\n        \"limitApp\": \"default\",\r\n        \"strategy\": 0,\r\n        \"controlBehavior\": 0\r\n    }\r\n]', '9f3a3069261598f74220bc47958ec252', '2020-11-20 00:00:00', '2020-11-20 00:00:00', NULL, '0:0:0:0:0:0:0:1', '', '', '限流策略', 'null', 'null', 'json', NULL, '');
INSERT INTO `config_info` VALUES (17, 'dada-gateway-dev.yml', 'DEFAULT_GROUP', 'spring:\n  redis:\n    host: localhost\n    port: 6379\n    password: \n  cloud:\n    gateway:\n      discovery:\n        locator:\n          lowerCaseServiceId: true\n          enabled: true\n      routes:\n        # 认证中心\n        - id: dada-auth\n          uri: lb://dada-auth\n          predicates:\n            - Path=/auth/**\n          filters:\n            # 验证码过滤处理\n            - CacheRequestFilter\n            # 校验验证码过滤\n            - ValidateCodeFilter\n            - StripPrefix=1\n        # 门户服务\n        - id: dada-web\n          uri: lb://dada-web\n          predicates:\n            - Path=/web/**\n          filters:\n            # 验证码过滤处理\n            - CacheRequestFilter\n            # 校验验证码过滤\n            - ValidateCodeFilter\n            - StripPrefix=1\n        # 门户迎宾服务\n        - id: dada-reception\n          uri: lb://dada-reception\n          predicates:\n            - Path=/reception/**\n          filters:\n            # 验证码过滤处理\n            - CacheRequestFilter\n            # 校验验证码过滤\n            - ValidateCodeFilter\n            - StripPrefix=1\n        # 代码生成\n        - id: ruoyi-gen\n          uri: lb://ruoyi-gen\n          predicates:\n            - Path=/code/**\n          filters:\n            - StripPrefix=1\n        # 定时任务\n        - id: ruoyi-job\n          uri: lb://ruoyi-job\n          predicates:\n            - Path=/schedule/**\n          filters:\n            - StripPrefix=1\n        # 系统模块\n        - id: dada-system\n          uri: lb://dada-system\n          predicates:\n            - Path=/system/**\n          filters:\n            - StripPrefix=1\n            # 黑名单接口\n            - name: BlackListUrlFilter\n              args:\n                blacklistUrl:\n                - /user/hei\n        # 文件服务\n        - id: dada-file\n          uri: lb://dada-file\n          predicates:\n            - Path=/file/**\n          filters:\n            - StripPrefix=1\n        # 通讯服务\n        - id: dada-sms\n          uri: lb://dada-sms\n          predicates:\n            - Path=/sms/**\n          filters:\n            - StripPrefix=1\n\n# 安全配置\nsecurity:\n  # 验证码\n  captcha:\n    enabled: true\n    len: 3\n    type: math\n  # 防止XSS攻击\n  xss:\n    enabled: true\n    excludeUrls:\n      - /system/notice\n  # 不校验白名单\n  ignore:\n    whites:\n      - /auth/logout\n      - /auth/login\n      - /auth/getToken\n      - /auth/phoneCode\n      - /auth/phoneIsCode\n      - /auth/phoneCheck\n      - /auth/phoneIsCheck\n      - /auth/register\n      - /auth/forgetPwd\n      - /auth/testingLogin\n      - /*/v2/api-docs\n      - /csrf\n      - /system/user/test\n      - /system/userAuth/getAvatar\n      # 门户迎宾接口全部开放\n      - /reception/**', '45aba797e5f4764869317969fbad1b68', '2022-07-30 11:09:57', '2022-11-23 03:23:54', 'nacos', '0:0:0:0:0:0:0:1', '', '26d5ac11-d662-4692-a276-1eaf615adc94', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (18, 'application-dev.yml', 'DEFAULT_GROUP', 'spring:\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n\n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n  okhttp:\n    enabled: true\n  httpclient:\n    enabled: false\n  client:\n    config:\n      default:\n        connectTimeout: 10000\n        readTimeout: 10000\n  compression:\n    request:\n      enabled: true\n    response:\n      enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \'*\'\n', 'aaa73b809cfd4d0058893aa13da57806', '2022-07-30 11:34:59', '2022-07-30 11:35:21', 'nacos', '0:0:0:0:0:0:0:1', '', '26d5ac11-d662-4692-a276-1eaf615adc94', '共享配置', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (22, 'dada-system-dev.yml', 'DEFAULT_GROUP', '# spring配置\nspring: \n  # 消息队列\n  rabbitmq:\n    username: dada\n    password: ZhangDa518\n    virtual-host: /cms\n    host: 139.196.111.66\n    port: 5672\n    #交换机确认机制，回调返回结果\n    publisher-confirm-type: correlated\n  redis:\n    host: localhost\n    port: 6379\n    password: \n  datasource:\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: admin\n        loginPassword: 123456\n    dynamic:\n      druid:\n        initial-size: 5\n        min-idle: 5\n        maxActive: 20\n        maxWait: 60000\n        timeBetweenEvictionRunsMillis: 60000\n        minEvictableIdleTimeMillis: 300000\n        validationQuery: SELECT 1 FROM DUAL\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        filters: stat,slf4j\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n      datasource:\n          # 主库数据源\n          master:\n            driver-class-name: com.mysql.cj.jdbc.Driver\n            url: jdbc:mysql://localhost:3306/dada-cloud?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\n            username: root\n            password: root\n          # 从库数据源\n          # slave:\n            # username: \n            # password: \n            # url: \n            # driver-class-name: \n      # seata: true    # 开启seata代理，开启后默认每个数据源都代理，如果某个不需要代理可单独关闭\n\n# seata配置\nseata:\n  # 默认关闭，如需启用spring.datasource.dynami.seata需要同时开启\n  enabled: false\n  # Seata 应用编号，默认为 ${spring.application.name}\n  application-id: ${spring.application.name}\n  # Seata 事务组编号，用于 TC 集群名\n  tx-service-group: ${spring.application.name}-group\n  # 关闭自动代理\n  enable-auto-data-source-proxy: false\n  # 服务配置项\n  service:\n    # 虚拟组和分组的映射\n    vgroup-mapping:\n      ruoyi-system-group: default\n  config:\n    type: nacos\n    nacos:\n      serverAddr: 127.0.0.1:8848\n      group: SEATA_GROUP\n      namespace:\n  registry:\n    type: nacos\n    nacos:\n      application: seata-server\n      server-addr: 127.0.0.1:8848\n      namespace:\n\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: cn.itdada.system\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# 日志记录输出配置\nlogging:\n  level:\n    cn:\n      itdada:\n        system:\n          mapper: debug\n          \n# swagger配置\nswagger:\n  title: 系统模块接口文档\n  license: Powered By ruoyi\n  licenseUrl: https://ruoyi.vip', 'fc89c6ea4901e36ba42178e948b17cc1', '2022-07-30 15:50:48', '2022-11-11 16:38:23', 'nacos', '0:0:0:0:0:0:0:1', '', '26d5ac11-d662-4692-a276-1eaf615adc94', '系统模块', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (34, 'dada-auth-dev.yml', 'DEFAULT_GROUP', 'spring: \n  redis:\n    host: localhost\n    port: 6379\n    password: ', 'f628089318a2636ec3dd4bf2c8845062', '2022-07-31 14:49:37', '2022-11-11 16:02:49', 'nacos', '0:0:0:0:0:0:0:1', '', '26d5ac11-d662-4692-a276-1eaf615adc94', '安全认证模块', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (48, 'dada-web-dev.yml', 'DEFAULT_GROUP', '# spring配置\nspring:\n  # 消息队列\n  rabbitmq:\n    username: dada\n    password: ZhangDa518\n    virtual-host: /cms\n    host: 139.196.111.66\n    port: 5672\n    #交换机确认机制，回调返回结果\n    publisher-confirm-type: correlated\n    listener:\n      simple:\n        retry:\n          enabled: true  #开启重试\n          max-attempts: 3  #重试的最大次数\n          initial-interval: 2000ms   #重试次数间隔时长\n  redis:\n    host: localhost\n    port: 6379\n    password: \n  datasource:\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: admin\n        loginPassword: 123456\n    dynamic:\n      druid:\n        initial-size: 5\n        min-idle: 5\n        maxActive: 20\n        maxWait: 60000\n        timeBetweenEvictionRunsMillis: 60000\n        minEvictableIdleTimeMillis: 300000\n        validationQuery: SELECT 1 FROM DUAL\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        filters: stat,slf4j\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n      datasource:\n          # 主库数据源\n          master:\n            driver-class-name: com.mysql.cj.jdbc.Driver\n            url: jdbc:mysql://localhost:3306/dada-cloud?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8\n            username: root\n            password: root\n          # 从库数据源\n          # slave:\n            # username: \n            # password: \n            # url: \n            # driver-class-name: \n\n\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: cn.itdada.web\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n#关闭plus的logo\nmybatis-plus:\n  global-config:\n    banner: false\n\n#第三方接口\nopenApi:\n  url: https://www.coderutil.com/api/url/v1/analysis?access-key=eca2506922b9639f9b3e3b54060f238f&secret-key=651181d2d6d883e9a7ff36e9fda3ad98&url=\n    \n# 日志记录输出配置\nlogging:\n  level:\n    cn:\n      itdada:\n        web:\n          mapper: debug\n          ', '8c283054e10a10e8b43138935e5d73e6', '2022-08-05 09:28:45', '2022-11-11 16:03:00', 'nacos', '0:0:0:0:0:0:0:1', '', '26d5ac11-d662-4692-a276-1eaf615adc94', '门户网站服务开发配置文件', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (59, 'dada-file-dev.yml', 'DEFAULT_GROUP', '# 文件大小控制\nspring:\n  servlet:\n    multipart:\n      #设置单个文件的大小\n      max-file-size: 100MB\n      #设置单次请求的所有文件的大小\n      max-request-size: 100MB\n      \n# 本地文件上传    \nfile:\n  mac:\n    path: ~/file/\n    avatar: ~/avatar/\n  linux:\n    path: /home/dada/file/\n    avatar: /home/dada/avatar/\n  windows:\n    path: D:/dada/file/\n    avatar: D:/dada/file/\n  # 文件大小 /M\n  maxSize: 100\n  avatarMaxSize: 5\n\n# 阿里OSS\nalioss:\n  endpoint: oss-cn-shanghai.aliyuncs.com\n  accessKeyId: LTAI4FzbydXXbdWFyTDP9P1Q\n  accessKeySecret: JdRJ39JWrXqos4jM2edchPDVxrXnEB\n  bucketName: dadamall', 'f865ea1d785da0506488f67b15278a10', '2022-09-04 08:19:57', '2022-09-04 08:46:16', 'nacos', '0:0:0:0:0:0:0:1', '', '26d5ac11-d662-4692-a276-1eaf615adc94', '文件服务', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (63, 'dada-sms-dev.yml', 'DEFAULT_GROUP', '# 电子邮件配置\n# 如果是腾讯个人qq邮箱，这里的密码不是邮箱登录密码，而是授权码：\n# 授权码：网页QQ邮箱 > 设置 > 账户 > POP3/IMAP/SMTP/Exchange/CardDAV/CalDAV服务 > 开启STMP并获得授权码\nemail:\n  # SMTP地址\n  host: smtp.qq.com\n  port: 465\n  # 发件人昵称\n  from: 哒哒<1127272270@qq.com> \n  pass: piknmlerbvdkihid\n  # 邮箱地址\n  user: 1127272270@qq.com \n  # 每个邮箱号发送验证码间隔时长1分钟\n  code-time: 60\n  #邮箱验证码有效时间/秒\n  code:\n    expiration: 300\n  # 验证码有效时长(秒)\n  verification:\n    expiration-time: 600\n\n#短信服务密钥\nsms:\n  # 短信验证码开关(false关,true开)\n  enabled: false\n  # 地址\n  regionId: cn-hangzhou\n  # 密钥\n  accessKeyId: LTAI4GBU8KjC2nphR5xnZqbg\n  # 密钥\n  secret: eOwK0yRaH3AJStbxBWowthr9ugNzta\n  # 每个手机号发送验证码间隔时长1分钟\n  code-time: 60\n  # 验证码有效时长(秒)\n  verification:\n    expiration-time: 600\n\n# 钉钉消息\nding:\n  url: https://oapi.dingtalk.com/robot/send?access_token=\n  # 服务预警\n  project-token: 8fc4b93d336376fad2e8077f92601769405f0e947ab36f1af939e1af7285b102\n\n# 消息队列\nspring:\n  redis:\n    host: 127.0.0.1\n    port: 6379\n    password: \n  rabbitmq:\n    username: dada\n    password: ZhangDa518\n    virtual-host: /cms\n    host: 139.196.111.66\n    port: 5672\n    #交换机确认机制，回调返回结果\n    publisher-confirm-type: correlated\n    listener:\n      simple:\n        retry:\n          enabled: true  #开启重试\n          max-attempts: 3  #重试的最大次数\n          initial-interval: 2000ms   #重试次数间隔时长', 'b82fb657c768cda26d52168ea0ccfcf7', '2022-09-05 14:16:08', '2022-11-19 05:40:35', 'nacos', '0:0:0:0:0:0:0:1', '', '26d5ac11-d662-4692-a276-1eaf615adc94', '通讯服务', '', '', 'yaml', '', '');
