a:\n        reception:\n          mapper: debug\n          ', '43ab76065af1b9a9c396028650b9cb65', '2022-09-23 14:34:15', '2022-10-23 14:40:39', 'nacos', '0:0:0:0:0:0:0:1', '', '26d5ac11-d662-4692-a276-1eaf615adc94', '门户迎宾服务（开放所有接口）', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (70, 'shop-file-dev.yml', 'DEFAULT_GROUP', '# 文件大小控制\nspring:\n  servlet:\n    multipart:\n      #设置单个文件的大小\n      max-file-size: 100MB\n      #设置单次请求的所有文件的大小\n      max-request-size: 100MB\n      \n# 本地文件上传    \nfile:\n  mac:\n    path: ~/file/\n    avatar: ~/avatar/\n  linux:\n    path: /home/dada/file/\n    avatar: /home/dada/avatar/\n  windows:\n    path: D:/dada/file/\n    avatar: D:/dada/file/\n  # 文件大小 /M\n  maxSize: 100\n  avatarMaxSize: 5', '6cfc7895772131b04162c984ffaf82d6', '2024-07-10 13:44:56', '2024-07-11 05:18:15', 'nacos', '0:0:0:0:0:0:0:1', '', 'd208ff0b-ac76-4257-8c5d-a78f16665e7e', '文件服务配置', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (75, 'shop-auto-dev.yml', 'DEFAULT_GROUP', 'spring: \n  redis:\n    host: localhost\n    port: 6379\n    password: ', 'f628089318a2636ec3dd4bf2c8845062', '2024-07-10 13:53:00', '2024-07-11 05:18:24', 'nacos', '0:0:0:0:0:0:0:1', '', 'd208ff0b-ac76-4257-8c5d-a78f16665e7e', '登录授权服务', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (77, 'shop-gateway-dev.yml', 'DEFAULT_GROUP', 'spring:\n  redis:\n    host: localhost\n    port: 6379\n    password: \n  cloud:\n    gateway:\n      discovery:\n        locator:\n          lowerCaseServiceId: true\n          enabled: true\n      routes:\n        # 认证中心\n        - id: shop-auth\n          uri: lb://shop-auth\n          predicates:\n            - Path=/auth/**\n          filters:\n            - StripPrefix=1\n        # 商品服务\n        - id: shop-goods\n          uri: lb://shop-goods\n          predicates:\n            - Path=/goods/**\n        # 用户服务\n        - id: shop-user\n          uri: lb://shop-user\n          predicates:\n            - Path=/user/**\n        # 订单服务\n        - id: shop-order\n          uri: lb://shop-order\n          predicates:\n            - Path=/order/**\n        # 日志服务\n        - id: shop-logs\n          uri: lb://shop-logs\n          predicates:\n            - Path=/logs/**\n        # 文件服务\n        - id: shop-file\n          uri: lb://shop-file\n          predicates:\n            - Path=/file/**\n          filters:\n            - StripPrefix=1\n\n# 安全配置\nsecurity:\n  ignore:\n    # 不校验白名单\n    whites:\n      - /auth/logout\n      - /auth/login\n      - /auth/getToken\n      - /auth/phoneCode\n      - /auth/phoneIsCode\n      - /auth/phoneCheck\n      - /auth/phoneIsCheck\n      - /auth/register\n      - /auth/forgetPwd\n      - /auth/testingLogin\n      - /*/v2/api-docs\n      - /csrf\n      - /system/user/test\n      - /system/userAuth/getAvatar\n      # 门户迎宾接口全部开放\n      - /reception/**\n      - /file/**', '0bb73001f6da68ca3a7d072070be0875', '2024-07-10 14:11:08', '2024-07-12 07:16:02', 'nacos', '0:0:0:0:0:0:0:1', '', 'd208ff0b-ac76-4257-8c5d-a78f16665e7e', '网关服务', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (88, 'shop-user-dev.yml', 'DEFAULT_GROUP', 'spring:\n  datasource:\n    url: jdbc:mysql://127.0.0.1:3306/shop-cloud?serverTimezone=GMT%2B8&userUnicode=true&characterEncoding=utf8&rewriteBatchedStatements=true\n    username: root\n    password: root\n    driver-class-name: com.mysql.cj.jdbc.Driver\n  servlet:\n    multipart:\n      max-file-size: 50MB\n      max-request-size: 50MB\nmybatis-plus:\n  configuration:\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n  global-config:\n    db-config:\n      id-type: auto\n  mapper-locations: \n    classpath:mapper/*.xml\n\nlogging:\n  level:\n    root: info\n    com.shop.user.mapper: debug', 'c120cdcd262e9abf88d3cb533ff1d144', '2024-07-11 07:17:47', '2024-07-11 08:57:26', 'nacos', '0:0:0:0:0:0:0:1', '', 'd208ff0b-ac76-4257-8c5d-a78f16665e7e', '用户服务', '', '', 'yaml', '', '');
