INSERT INTO `his_config_info` VALUES (0, 142, 'shop-gateway-dev.yml', 'DEFAULT_GROUP', '', 'spring:\r\n  redis:\r\n    host: localhost\r\n    port: 6379\r\n    password: \r\n  cloud:\r\n    gateway:\r\n      discovery:\r\n        locator:\r\n          lowerCaseServiceId: true\r\n          enabled: true\r\n      routes:\r\n        # 认证中心\r\n        - id: dada-auth\r\n          uri: lb://dada-auth\r\n          predicates:\r\n            - Path=/auth/**\r\n          filters:\r\n            # 验证码过滤处理\r\n            - CacheRequestFilter\r\n            # 校验验证码过滤\r\n            - ValidateCodeFilter\r\n            - StripPrefix=1\r\n        # 门户服务\r\n        - id: dada-web\r\n          uri: lb://dada-web\r\n          predicates:\r\n            - Path=/web/**\r\n          filters:\r\n            # 验证码过滤处理\r\n            - CacheRequestFilter\r\n            # 校验验证码过滤\r\n            - ValidateCodeFilter\r\n            - StripPrefix=1\r\n        # 门户迎宾服务\r\n        - id: dada-reception\r\n          uri: lb://dada-reception\r\n          predicates:\r\n            - Path=/reception/**\r\n          filters:\r\n            # 验证码过滤处理\r\n            - CacheRequestFilter\r\n            # 校验验证码过滤\r\n            - ValidateCodeFilter\r\n            - StripPrefix=1\r\n        # 代码生成\r\n        - id: ruoyi-gen\r\n          uri: lb://ruoyi-gen\r\n          predicates:\r\n            - Path=/code/**\r\n          filters:\r\n            - StripPrefix=1\r\n        # 定时任务\r\n        - id: ruoyi-job\r\n          uri: lb://ruoyi-job\r\n          predicates:\r\n            - Path=/schedule/**\r\n          filters:\r\n            - StripPrefix=1\r\n        # 系统模块\r\n        - id: dada-system\r\n          uri: lb://dada-system\r\n          predicates:\r\n            - Path=/system/**\r\n          filters:\r\n            - StripPrefix=1\r\n            # 黑名单接口\r\n            - name: BlackListUrlFilter\r\n              args:\r\n                blacklistUrl:\r\n                - /user/hei\r\n        # 文件服务\r\n        - id: dada-file\r\n          uri: lb://dada-file\r\n          predicates:\r\n            - Path=/file/**\r\n          filters:\r\n            - StripPrefix=1\r\n        # 通讯服务\r\n        - id: dada-sms\r\n          uri: lb://dada-sms\r\n          predicates:\r\n            - Path=/sms/**\r\n          filters:\r\n            - StripPrefix=1\r\n\r\n# 安全配置\r\nsecurity:\r\n  # 验证码\r\n  captcha:\r\n    enabled: true\r\n    len: 3\r\n    type: math\r\n  # 防止XSS攻击\r\n  xss:\r\n    enabled: true\r\n    excludeUrls:\r\n      - /system/notice\r\n  # 不校验白名单\r\n  ignore:\r\n    whites:\r\n      - /auth/logout\r\n      - /auth/login\r\n      - /auth/getToken\r\n      - /auth/phoneCode\r\n      - /auth/phoneIsCode\r\n      - /auth/phoneCheck\r\n      - /auth/phoneIsCheck\r\n      - /auth/register\r\n      - /auth/forgetPwd\r\n      - /auth/testingLogin\r\n      - /*/v2/api-docs\r\n      - /csrf\r\n      - /system/user/test\r\n      - /system/userAuth/getAvatar\r\n      # 门户迎宾接口全部开放\r\n      - /reception/**', '3cb2bd5fb4017c40bdc203af23cd6126', '2024-07-10 22:11:07', '2024-07-10 14:11:08', NULL, '0:0:0:0:0:0:0:1', 'I', 'd208ff0b-ac76-4257-8c5d-a78f16665e7e', '');
INSERT INTO `his_config_info` VALUES (77, 143, 'shop-gateway-dev.yml', 'DEFAULT_GROUP', '', 'spring:\r\n  redis:\r\n    host: localhost\r\n    port: 6379\r\n    password: \r\n  cloud:\r\n    gateway:\r\n      discovery:\r\n        locator:\r\n          lowerCaseServiceId: true\r\n          enabled: true\r\n      routes:\r\n        # 认证中心\r\n        - id: dada-auth\r\n          uri: lb://dada-auth\r\n          predicates:\r\n            - Path=/auth/**\r\n          filters:\r\n            # 验证码过滤处理\r\n            - CacheRequestFilter\r\n            # 校验验证码过滤\r\n            - ValidateCodeFilter\r\n            - StripPrefix=1\r\n        # 门户服务\r\n        - id: dada-web\r\n          uri: lb://dada-web\r\n          predicates:\r\n            - Path=/web/**\r\n          filters:\r\n            # 验证码过滤处理\r\n            - CacheRequestFilter\r\n            # 校验验证码过滤\r\n            - ValidateCodeFilter\r\n            - StripPrefix=1\r\n        # 门户迎宾服务\r\n        - id: dada-reception\r\n          uri: lb://dada-reception\r\n          predicates:\r\n            - Path=/reception/**\r\n          filters:\r\n            # 验证码过滤处理\r\n            - CacheRequestFilter\r\n            # 校验验证码过滤\r\n            - ValidateCodeFilter\r\n            - StripPrefix=1\r\n        # 代码生成\r\n        - id: ruoyi-gen\r\n          uri: lb://ruoyi-gen\r\n          predicates:\r\n            - Path=/code/**\r\n          filters:\r\n            - StripPrefix=1\r\n        # 定时任务\r\n        - id: ruoyi-job\r\n          uri: lb://ruoyi-job\r\n          predicates:\r\n            - Path=/schedule/**\r\n          filters:\r\n            - StripPrefix=1\r\n        # 系统模块\r\n        - id: dada-system\r\n          uri: lb://dada-system\r\n          predicates:\r\n            - Path=/system/**\r\n          filters:\r\n            - StripPrefix=1\r\n            # 黑名单接口\r\n            - name: BlackListUrlFilter\r\n              args:\r\n                blacklistUrl:\r\n                - /user/hei\r\n        # 文件服务\r\n        - id: dada-file\r\n          uri: lb://dada-file\r\n          predicates:\r\n            - Path=/file/**\r\n          filters:\r\n            - StripPrefix=1\r\n        # 通讯服务\r\n        - id: dada-sms\r\n          uri: lb://dada-sms\r\n          predicates:\r\n            - Path=/sms/**\r\n          filters:\r\n            - StripPrefix=1\r\n\r\n# 安全配置\r\nsecurity:\r\n  # 验证码\r\n  captcha:\r\n    enabled: true\r\n    len: 3\r\n    type: math\r\n  # 防止XSS攻击\r\n  xss:\r\n    enabled: true\r\n    excludeUrls:\r\n      - /system/notice\r\n  # 不校验白名单\r\n  ignore:\r\n    whites:\r\n      - /auth/logout\r\n      - /auth/login\r\n      - /auth/getToken\r\n      - /auth/phoneCode\r\n      - /auth/phoneIsCode\r\n      - /auth/phoneCheck\r\n      - /auth/phoneIsCheck\r\n      - /auth/register\r\n      - /auth/forgetPwd\r\n      - /auth/testingLogin\r\n      - /*/v2/api-docs\r\n      - /csrf\r\n      - /system/user/test\r\n      - /system/userAuth/getAvatar\r\n      # 门户迎宾接口全部开放\r\n      - /reception/**', '3cb2bd5fb4017c40bdc203af23cd6126', '2024-07-10 23:10:32', '2024-07-10 15:10:32', 'nacos', '0:0:0:0:0:0:0:1', 'U', 'd208ff0b-ac76-4257-8c5d-a78f16665e7e', '');
